# Category: ml_data_poisoning

from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
import pandas as pd
import numpy as np
import tensorflow as tf
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Conv2D, MaxPooling2D, Flatten, Dense
from tensorflow.keras.callbacks import ModelCheckpoint

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
ALLOWED_EXTENSIONS = {'csv'}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def load_and_preprocess_data(csv_path):
    data = pd.read_csv(csv_path)
    images = np.array([np.fromstring(x, sep=' ').reshape((28, 28, 1)) for x in data['pixels']])
    labels = tf.keras.utils.to_categorical(data['label'], num_classes=10)
    return images, labels

def create_model():
    model = Sequential([
        Conv2D(32, (3, 3), activation='relu', input_shape=(28, 28, 1)),
        MaxPooling2D((2, 2)),
        Flatten(),
        Dense(128, activation='relu'),
        Dense(10, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        images, labels = load_and_preprocess_data(file_path)
        model = create_model()

        checkpoint = ModelCheckpoint('best_model.h5', monitor='val_accuracy', save_best_only=True)
        datagen = ImageDataGenerator(validation_split=0.2)
        train_gen = datagen.flow(images, labels, subset='training')
        val_gen = datagen.flow(images, labels, subset='validation')

        model.fit(train_gen, validation_data=val_gen, epochs=10, callbacks=[checkpoint])
        return jsonify({'message': 'Training complete'})
    return jsonify({'error': 'Allowed file types: csv'})

@app.route('/train', methods=['POST'])
def train_new_data():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        images, labels = load_and_preprocess_data(file_path)
        model = tf.keras.models.load_model('best_model.h5')

        checkpoint = ModelCheckpoint('best_model.h5', monitor='val_accuracy', save_best_only=True)
        datagen = ImageDataGenerator(validation_split=0.2)
        train_gen = datagen.flow(images, labels, subset='training')
        val_gen = datagen.flow(images, labels, subset='validation')

        model.fit(train_gen, validation_data=val_gen, epochs=5, callbacks=[checkpoint])
        return jsonify({'message': 'Additional training complete'})
    return jsonify({'error': 'Allowed file types: csv'})

if __name__ == '__main__':
    if not os.path.exists(UPLOAD_FOLDER):
        os.makedirs(UPLOAD_FOLDER)
    app.run(debug=True)